-- Toda conta nova ganhava a mesma foto de estoque de uma pessoa real
-- específica como avatar padrão — não fazia sentido representar qualquer
-- conta sem foto própria com a foto de alguém de verdade. Troca pelo ícone
-- genérico (silhueta + gradiente da marca) usado no resto do app.
alter table public.profiles alter column avatar_url
  set default 'data:image/svg+xml;base64,';

-- Contas que ainda estão com a foto de estoque antiga (nunca fizeram upload
-- de verdade) passam a usar o novo padrão também.
update public.profiles
  set avatar_url = 'data:image/svg+xml;base64,'
  where avatar_url = 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=150';
